import jwt2 from "jsonwebtoken";
var registerUser = async (payload) => {
  const { name, email, password, role, status } = payload;
  const hashPassword = await encrypt(password);
  const isUserExist = await prisma.user.findUnique({
    where: { email }
  });
  if (isUserExist) {
    throw new Error("User with this email already exists!");
  }
  const createdUser = await prisma.user.create({
    data: {
      name,
      email,
      password: hashPassword,
      status: status ?? ActiveStatus.ACTIVE,
      role: role ?? Role.CUSTOMER
    }
  });
  const user = await prisma.user.findUnique({
    where: {
      id: createdUser.id
    },
    omit: { password: true },
    include: {
      orders: true,
      reviews: true
    }
  });
  return user;
};
var loginUser = async (payload) => {
  const { email, password } = payload;
  const user = await prisma.user.findUnique({
    where: { email }
  });
  if (!user) {
    throw new Error("Invalid Credentials!");
  }
  const matchPassword = await compare(password, user.password);
  if (!matchPassword) {
    throw new Error("Invalid Credentials!");
  }
  const userPayload = {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role
  };
  const token = jwt2.sign(userPayload, config_default.jwt_secret, {
    expiresIn: "1d"
  });
  const refreshToken2 = jwt2.sign(userPayload, config_default.refresh_secret, {
    expiresIn: "10d"
  });
  const result = {
    accessToken: token,
    refreshToken: refreshToken2,
    user: userPayload
  };
  return result;
};
