var generateRefreshToken = async (token) => {
  if (!token) {
    throw new Error("Unauthorized");
  }
  const decodedToken = jwt2.verify(
    token,
    config_default.refresh_secret
  );
  const userData = await prisma.user.findUnique({
    where: {
      id: decodedToken.id
    }
  });
  if (!userData) {
    throw new Error("User not Found");
  }
  const userPayload = {
    id: userData.id,
    name: userData.name,
    role: userData.role
  };
  const accessToken = jwt2.sign(userPayload, config_default.jwt_secret, {
    expiresIn: "1d"
  });
  return { accessToken };
};
