import httpStatus3 from "http-status";
import "jsonwebtoken";
var authAsync = (...roles) => {
  return catchAsync(async (req, res, next) => {
    const token = req.cookies.accessToken ? req.cookies.accessToken : req.headers.authorization?.startsWith("Bearer ") ? req.headers.authorization?.split(" ")[1] : req.headers.authorization;
    if (!token) {
      throw new Error(
        "Unauthorized access! Please log in to access this resource"
      );
    }
    const verifiedToken = await verifyToken(
      token,
      config_default.jwt_secret
    );
    if (!verifiedToken.success && !verifiedToken.data) {
      throw new Error(verifiedToken.error);
    }
    const { id, name, email, role } = verifiedToken.data;
    const user = await prisma.user.findUnique({
      where: {
        email
      },
      omit: {
        password: true
      }
    });
    if (user?.status === "SUSPENDED") {
      sendReponse_default(res, {
        statusCode: httpStatus3.UNAUTHORIZED,
        success: false,
        message: "Access forbidden as your account has been suspended",
        data: {}
      });
    }
    if (roles.length && user && !roles.includes(user.role)) {
      sendReponse_default(res, {
        statusCode: httpStatus3.UNAUTHORIZED,
        success: false,
        message: "Access forbidden with your role.",
        data: {}
      });
    }
    req.user = verifiedToken;
    next();
  });
};

