import "stripe";
import httpStatus10 from "http-status";
var handleStripeWebhook = async (req, res, next) => {
  const signature = req.headers["stripe-signature"];
  let event;
  try {
    event = stripeClient.webhooks.constructEvent(
      req.body,
      // raw Buffer — see route setup
      signature,
      config_default.stripe_webhook_secret
    );
  } catch (error) {
    console.error("Webhook signature verification failed:", error);
    return res.status(httpStatus10.BAD_REQUEST).send("Webhook signature verification failed.");
  }
  switch (event.type) {
    case "checkout.session.completed": {
      try {
        const session = event.data.object;
        const rentalOrderId = session.metadata?.rentalOrderId;
        if (!rentalOrderId) {
          console.error("No rentalOrderId in session metadata");
          break;
        }
        await prisma.$transaction([
          prisma.payment.update({
            where: { transactionId: session.id },
            data: {
              status: "COMPLETED"
            }
          }),
          prisma.rentalOrder.update({
            where: { id: rentalOrderId },
            data: { status: "CONFIRMED" }
          })
        ]);
      } catch (error) {
        console.error("Failed to process checkout.session.completed:", error);
      }
      break;
    }
    case "checkout.session.expired": {
      const session = event.data.object;
      const rentalOrderId = session.metadata?.rentalOrderId;
      if (!rentalOrderId) break;
      await prisma.$transaction([
        prisma.payment.update({
          where: { transactionId: session.id },
          data: { status: "FAILED" }
        }),
        prisma.rentalOrder.update({
          where: { id: rentalOrderId },
          data: { status: "FAILED" }
        })
      ]);
      break;
    }
    default:
      break;
  }
  sendReponse_default(res, {
    statusCode: httpStatus10.OK,
    success: true,
    message: "Rental order updated after payment successfully!",
    data: { received: true }
  });
};
var webhookController = {
  handleStripeWebhook
};

